#include <stdio.h>
#include <string.h>
#define MAX_VISITS 200000
#define MAX_ROOMS 500
#define MAX_NAME_LENGTH 10

int calculateRoomNumber(char *name, int R) {
    int sum = 0;
    for (int i = 0; i < strlen(name); i++) {
        sum = sum * 33 + (name[i] - 'a' + 1);
    }
    return sum % R;
}

int applyLiftBoysScheme(int roomNumber, int R, int *rooms, int *guests, int *departureTimes) {
    int sequence[] = {1, 2, 3, 6, 11, 20, 37};
    int sequenceIndex = 0;
    while (sequenceIndex < 7) {
        int nextRoomNumber = (roomNumber + sequence[sequenceIndex]) % R;
        if (rooms[nextRoomNumber] == 0) {
            return nextRoomNumber;
        }
        sequenceIndex++;
    }
    return -1;
}

